// HMR for JavaScript modules
import { renderApp } from './app';

renderApp();

if (module.hot) {
  module.hot.accept('./app', () => {
    const { renderApp } = require('./app');
    renderApp();  // re-render without losing state
  });
}

// HMR for CSS — works automatically with style-loader
import './styles.css';
// No accept handler needed — CSS updates apply instantly

// HMR for React — react-refresh
// Install: @pmmmwh/react-refresh-webpack-plugin react-refresh
const ReactRefreshWebpackPlugin = require('@pmmmwh/react-refresh-webpack-plugin');

module.exports = {
  plugins: [
    new webpack.HotModuleReplacementPlugin(),
    new ReactRefreshWebpackPlugin(),
  ],
  module: {
    rules: [{
      test: /\.jsx?$/,
      use: {
        loader: 'babel-loader',
        options: {
          plugins: ['react-refresh/babel'],
        },
      },
    }],
  },
};
