// webpack.config.js
const TerserPlugin = require('terser-webpack-plugin');
const { BundleAnalyzerPlugin } = require('webpack-bundle-analyzer');
const CompressionPlugin = require('compression-webpack-plugin');

module.exports = {
  mode: 'production',
  devtool: 'source-map',  // separate .map file for error tracking
  optimization: {
    minimize: true,
    minimizer: [
      new TerserPlugin({
        terserOptions: {
          compress: {
            drop_console: true,   // remove console.log
            drop_debugger: true,
          },
          mangle: true,
        },
      }),
    ],
    splitChunks: {
      chunks: 'all',
      maxSize: 250000,  // split chunks > 250KB
    },
    runtimeChunk: 'single',  // separate runtime for long-term caching
  },
  plugins: [
    // Gzip compression
    new CompressionPlugin({
      algorithm: 'gzip',
      test: /\.(js|css|html|svg)$/,
      threshold: 10240,
      minRatio: 0.8,
    }),
    // Bundle analysis (run with ANALYZE=true)
    ...(process.env.ANALYZE ? [new BundleAnalyzerPlugin()] : []),
  ],
};
